def compute_statistics(values: list[float]) -> dict:
    if not values:
        return {"count": 0, "sum": 0, "min": None, "max": None, "average": None}
    total = sum(values)
    count = len(values)
    return {
        "count": count,
        "sum": total,
        "min": min(values),
        "max": max(values),
        "average": total / count,
    }
